  --accent: #34d399; /* Emerald 400 */
  --accent-hover: #10b981; /* Emerald 500 */
  --muted: #a8a29e; /* Stone 400 - Good contrast on dark */
  --code-fg: #e7e5e4; /* Stone 200 - High contrast neutral */
}

/* Palette Overrides */
/* Blue */
[data-palette="blue"] {
  --accent: #2563eb; /* Blue 600 */
  --accent-hover: #1d4ed8;
}
.dark[data-palette="blue"] {
  --accent: #60a5fa; /* Blue 400 */
  --accent-hover: #3b82f6;
}

