import ShareBar from '@/components/ShareBar';
import { siteConfig } from '../../site.config';
import { t } from '@/lib/i18n';
import { getPostUrl } from '@/lib/urls';

interface PostLayoutProps {
  post: PostData;
  relatedPosts?: PostData[];
  seriesPosts?: PostData[];
  seriesTitle?: string;
  prevPost?: PostData | null;
  nextPost?: PostData | null;
  backlinks?: BacklinkSource[];
  slugRegistry?: Map<string, SlugRegistryEntry>;
}

export default function PostLayout({ post, relatedPosts, seriesPosts, seriesTitle, prevPost, nextPost, backlinks, slugRegistry }: PostLayoutProps) {
  const showToc = siteConfig.posts?.toc !== false && post.toc !== false && post.headings && post.headings.length > 0;
  const hasSeries = !!(post.series && seriesPosts && seriesPosts.length > 0);
  const showSidebar = showToc || hasSeries;
  const postUrl = `${siteConfig.baseUrl}${getPostUrl(post)}`;

  return (
    <div className="layout-container">
      <ReadingProgressBar />
      <div className={showSidebar
        ? 'grid grid-cols-1 lg:grid-cols-[280px_minmax(0,1fr)] gap-8 items-start'
        : 'max-w-6xl mx-auto'
      }>
        {/* Left sidebar: series nav + page TOC */}
        {showSidebar && (
          <PostSidebar
            seriesSlug={hasSeries ? post.series : undefined}
            seriesTitle={hasSeries ? (seriesTitle || post.series) : undefined}
            posts={hasSeries ? seriesPosts : undefined}
            currentSlug={post.slug}
            headings={showToc ? post.headings : []}
            shareUrl={postUrl}
            shareTitle={post.title}
          />
        )}

        <article className="min-w-0 max-w-3xl mx-auto">
          <header className="mb-16 border-b border-muted/10 pb-8">
            {post.draft && (
              <div className="mb-4">
                <span className="text-xs font-bold text-red-500 bg-red-100 dark:bg-red-900/30 px-2 py-1 rounded tracking-widest inline-block">
                  DRAFT
                </span>
              </div>
            )}
            <div className="flex items-center gap-3 text-xs font-sans text-muted mb-6">
              <span className="uppercase tracking-widest font-semibold text-accent">
                {post.category}
              </span>
              <span className="w-1 h-1 rounded-full bg-muted/30" />
              <time className="font-mono" data-pagefind-meta="date[content]">{post.date}</time>
              <span className="w-1 h-1 rounded-full bg-muted/30" />
              <span className="font-mono">{post.readingTime}</span>
            </div>

            <h1 className="text-4xl md:text-5xl font-serif font-bold text-heading leading-tight mb-4">
              {post.title}
            </h1>

            {post.subtitle && (
              <p className="text-xl md:text-2xl font-serif italic text-muted leading-snug mb-6">
                {post.subtitle}
              </p>
            )}

            {siteConfig.posts?.authors?.showInHeader !== false && post.authors.length > 0 && (
              <div className="flex items-center gap-2 mb-8 text-sm font-serif italic text-muted">
                <span>{t('written_by')}</span>
                <div className="flex items-center gap-1">
                  {post.authors.map((author, index) => (
                    <span key={author} className="flex items-center">
                      <Link
                        href={`/authors/${getAuthorSlug(author)}`}
                        className="text-foreground hover:text-accent no-underline transition-colors duration-200"
                      >
                        {author}
                      </Link>
                      {index < post.authors.length - 1 && <span className="mr-1">,</span>}
                    </span>
                  ))}
                </div>
              </div>
            )}

            {post.excerpt && (
              <p className="text-xl text-foreground font-serif italic leading-relaxed mb-8">
                {post.excerpt}
              </p>
            )}

            {post.tags && post.tags.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {post.tags.map((tag) => (
                  <Tag key={tag} tag={tag} variant="default" />
                ))}
              </div>
            )}
          </header>

          {hasSeries && (
            <div className="lg:hidden mb-12">
              <SeriesList seriesSlug={post.series!} seriesTitle={seriesTitle || post.series!} posts={seriesPosts!} currentSlug={post.slug} />
            </div>
          )}

          <MarkdownRenderer content={post.content} latex={post.latex} slug={`posts/${post.slug}`} slugRegistry={slugRegistry} />

          {siteConfig.posts?.authors?.showAuthorCard !== false && (
            <AuthorCard authors={post.authors} />
          )}

          {post.tags && post.tags.length > 0 && (
            <div className="mt-12 pt-12 border-t border-muted/20 flex flex-wrap items-center gap-2">
              <span className="text-[10px] font-sans font-bold uppercase tracking-widest text-muted mr-1">{t('tags')}</span>
              {post.tags.map((tag) => (
                <Tag key={tag} tag={tag} variant="default" />
              ))}
            </div>
          )}

          <Backlinks backlinks={backlinks ?? []} />

          <ShareBar
            url={postUrl}
            title={post.title}
            className={showSidebar ? 'mt-8 lg:hidden' : 'mt-8'}
          />

          {siteConfig.posts?.authors?.showAuthorCard !== false && (
            <AuthorCard authors={post.authors} />
          )}

          <Comments slug={post.slug} postUrl={postUrl} />

          {post.externalLinks && post.externalLinks.length > 0 && (
            <ExternalLinks links={post.externalLinks} />
          )}

          <PostNavigation prev={prevPost ?? null} next={nextPost ?? null} />

          <RelatedPosts posts={relatedPosts || []} />
        </article>
      </div>
    </div>
  );
}

import Link from 'next/link';
import ExportedImage from 'next-image-export-optimizer';
import { getAuthorSlug } from '@/lib/markdown';
import { siteConfig } from '../../site.config';
import { t } from '@/lib/i18n';

const isDev = process.env.NODE_ENV === 'development';
const isExternal = (src: string) => src.startsWith('http') || src.startsWith('//');

export default function AuthorCard({ authors }: { authors: string[] }) {
  if (!authors || authors.length === 0) return null;

  return (
    <div className="mt-12 pt-12 border-t border-muted/20 flex flex-col gap-4">
      {authors.map((author) => {
        const slug = getAuthorSlug(author);
        const profile = siteConfig.authors?.[author];
        const hasSocial = profile?.social && profile.social.length > 0;

        return (
          <div
            key={author}
            className="flex flex-col sm:flex-row sm:items-center gap-5 rounded-2xl border border-muted/15 bg-muted/[0.04] px-6 py-5 transition-colors hover:bg-muted/[0.08]"
          >
            {/* Left — avatar + author info */}
            <div className="flex items-start gap-4 flex-1 min-w-0">
              {profile?.avatar ? (
                <ExportedImage
                  src={profile.avatar}
                  alt={author}
                  width={56}
                  height={56}
                  className="w-14 h-14 rounded-full object-cover flex-shrink-0 ring-2 ring-muted/20"
                  unoptimized={isDev || isExternal(profile.avatar)}
                />
              ) : (
                <div className="w-14 h-14 rounded-full bg-accent/10 flex items-center justify-center flex-shrink-0 text-accent font-serif font-bold text-2xl select-none">
                  {author.charAt(0).toUpperCase()}
                </div>
              )}

              <div className="min-w-0">
                <p className="text-[10px] font-sans font-bold uppercase tracking-widest text-muted mb-1">
                  {t('written_by')}
                </p>
                <Link
                  href={`/authors/${slug}`}
                  className="font-serif font-semibold text-lg text-heading hover:text-accent transition-colors no-underline"
                >
                  {author}
                </Link>
                {profile?.bio && (
                  <p className="text-sm text-foreground/70 mt-1.5 leading-relaxed">
                    {profile.bio}
                  </p>
                )}
              </div>
            </div>

            {/* Right — social images (e.g. QR codes) */}
            {hasSocial && (
              <div className="flex justify-center gap-5 flex-shrink-0 border-t border-muted/15 pt-4 sm:border-t-0 sm:border-l sm:pt-0 sm:pl-6 sm:justify-start">
                {profile.social!.map((item, index) => (
                  <figure key={index} className="flex flex-col items-center gap-1.5">
                    <ExportedImage
                      src={item.image}
                      alt={item.description}
                      width={72}
                      height={72}
                      className="w-[72px] h-[72px] object-contain rounded-lg bg-white p-0.5"
                      unoptimized={isDev || isExternal(item.image)}
                    />
                    <figcaption className="text-[10px] font-sans text-muted text-center leading-tight max-w-[72px]">
                      {item.description}
                    </figcaption>
                  </figure>
                ))}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}
